async function main() {
  const res = await sheets.spreadsheets.values.get({
    spreadsheetId,
    range: "Posts!A:F",
  });
  const vals = res.data.values || [];
  const lastRow = vals.length + 1;

  const rows = posts.map((p) => [
    p[0], p[1], p[2], p[3], p[4], p[5]
  ]);

  const updateRes = await sheets.spreadsheets.values.update({
    spreadsheetId,
    range: `Posts!A${lastRow}:F${lastRow + rows.length - 1}`,
    valueInputOption: "USER_ENTERED",
    requestBody: { values: rows },
  });

  console.log(`✅ Queued ${posts.length} Men's Mental Health posts starting at row ${lastRow}`);
  console.log("Updated range: " + updateRes.data.updates.updatedRange);
}

main().catch(console.error);
